def validate_email(text: str) -> bool:
    if text.strip() == "":
        return False
    if text.count("@") != 1:
        return False
    local, domain = text.split("@")
    if local == "" or domain == "":
        return False
    if "." not in domain:
        return False
    if domain.startswith(".") or domain.endswith("."):
        return False
    return True
